import java.text.SimpleDateFormat;
 import java.text.ParseException;
 import sailpoint.tools.Util;
 if(value!=null)
 {
   try
   {
     System.out.println("value****"+value);
    
     Date today=new Date();
     if(value!=null){
       int diff= Util.getDaysDifference(value,today);
       System.out.println("diff****"+diff);
       if(!(diff>0 @and diff<367)){
           return "Please select date range between below 365 days";
       }
     }else{
             return "Its mandatory to select the date";
     }
   }
   catch (Exception ex)
   {
     return "Invalid Date Format";
   }
